sys_script_include.script:
var TableWidgetRecordEnricher = Class.create();
TableWidgetRecordEnricher.prototype = {
    initialize: function (options) {
        options = options || {};
        this.normalizer = options.normalizer;
        this.sanitizer = options.sanitizer;
    },

    decorateRecords: function (widgetHelper, records, columns) {
        var normalizer = this.normalizer;
        var sanitizer = this.sanitizer;
        var hasContextMenu =
            typeof widgetHelper.getContextMenuItems === "function";
        var rowClickAction =
            typeof widgetHelper.getRowClickAction === "function"
                ? widgetHelper.getRowClickAction()
                : {};
        var clickAction = rowClickAction.action || {};

        return (records || []).map(function (record) {
            var decoratedRecord = Object.assign({}, record);
            decoratedRecord.__cellContent = {};

            for (var i = 0; i < columns.length; i++) {
                var field = columns[i];
                decoratedRecord.__cellContent[field.name] =
                    normalizer.normalizeCellContent(
                        widgetHelper.getCellContent(field, record),
                        sanitizer,
                    );
            }

            if (hasContextMenu) {
                decoratedRecord.__contextMenuItems =
                    normalizer.normalizeContextMenuItems(
                        widgetHelper.getContextMenuItems(record),
                        sanitizer,
                    );
            }

            // Preserve provider-level link fields in plain object records.
            if (clickAction.type === "link" && clickAction.urlField) {
                var urlField = clickAction.urlField;
                if (
                    !decoratedRecord.hasOwnProperty(urlField) &&
                    record.hasOwnProperty(urlField)
                ) {
                    decoratedRecord[urlField] = record[urlField];
                }
            }

            return decoratedRecord;
        });
    },

    type: "TableWidgetRecordEnricher",
};
